"""
Duke Extension Generator & Handler Launcher
Usage: python3 duke_generate.py <listen_ip> <listen_port> <callback_ip> <callback_port>

Generates duke.zip (Chrome extension) configured to call back to
callback_ip:callback_port, then starts the interactive proxy handler
bound to listen_ip:listen_port.
"""

