def print_status():
    with LOCK:
        connected  = CONN_STATE['connected']
        client_ip  = CONN_STATE['client_ip']
        first_seen = CONN_STATE['first_seen']
        last_seen  = CONN_STATE['last_seen']
        polls      = CONN_STATE['poll_count']
        results    = CONN_STATE['result_count']
        preloads   = sum(1 for k in RESULT_STORE if isinstance(k, str) and k.startswith('preload_'))

    if not connected:
        print(f"  {RED}{BOLD}[DISCONNECTED]{RESET} No extension has connected yet")
        print(f"  {YELLOW}Ensure the extension is loaded and polling this handler{RESET}")
        return

    now = time.time()
    ago    = now - last_seen if last_seen else 0
    uptime = now - first_seen if first_seen else 0

    if ago < 5:
        sc, st = GREEN, "ALIVE"
    elif ago < 15:
        sc, st = YELLOW, "STALE"
    else:
        sc, st = RED, "DEAD"

    print(f"  {sc}{BOLD}[{st}]{RESET} Extension proxy status")
    print(f"  {BLUE}Client IP:{RESET}     {client_ip}")
    print(f"  {BLUE}First seen:{RESET}    {time.strftime('%H:%M:%S', time.localtime(first_seen))}")
    print(f"  {BLUE}Last seen:{RESET}     {time.strftime('%H:%M:%S', time.localtime(last_seen))} ({ago:.1f}s ago)")
    print(f"  {BLUE}Uptime:{RESET}        {uptime:.1f}s")
    print(f"  {BLUE}Polls:{RESET}         {polls}")
    print(f"  {BLUE}Results:{RESET}       {results}")
    print(f"  {BLUE}Preloads:{RESET}      {preloads} cached")
    print(f"  {BLUE}Queue:{RESET}         {TASK_QUEUE.qsize()} pending task(s)")
    with LOCK:
        lcount = len(LISTENERS)
    print(f"  {BLUE}Listeners:{RESET}    {lcount} active")
    with LOCK:
        cur_url = ACTIVE_TAB['url']
        cur_title = ACTIVE_TAB['title']
    if cur_url:
        label = cur_title if cur_title else cur_url
        if len(label) > 55:
            label = label[:52] + '...'
        print(f"  {BLUE}Current URL:{RESET}  {CYAN}{label}{RESET}")
